head.b:skin:
:root {
  /* ULTIMATE GAMER / TECH PALETTE */
  --bg-dark: #050508;
  --bg-panel: rgba(12, 12, 20, 0.75);
  --bg-card: rgba(20, 20, 32, 0.85);
  --primary: #00f0ff;    /* Cyber Cyan */
  --secondary: #b026ff;  /* Neon Purple */
  --terminal: #00ff41;   /* Hacker Green */
  --alert: #ff003c;      /* Error Red */

  --text-main: #f8fafc;
  --text-muted: #94a3b8;

  --font-display: 'Orbitron', sans-serif;
  --font-code: 'JetBrains Mono', monospace;
  --font-body: 'Inter', sans-serif;

  --border-glow: 0 0 10px rgba(0, 240, 255, 0.3);
  --border-glow-hover: 0 0 20px rgba(0, 240, 255, 0.6), inset 0 0 10px rgba(0, 240, 255, 0.2);
}

* { margin:0; padding:0; box-sizing:border-box; }
::selection { background: var(--primary); color: #000; }
html { scroll-behavior: smooth; }
body {
  font-family: var(--font-body);
  font-size: 1.05rem;
  background: var(--bg-dark);
  color: var(--text-main);
  overflow-x: hidden;
  line-height: 1.6;
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-display);
  text-transform: uppercase;
  letter-spacing: 1px;
  color: var(--text-main);
}
a { text-decoration: none; color: inherit; transition: all 0.3s ease; }

/* ── COMMAND LINE BOOT SCREEN ── */
#boot-screen {
  position: fixed; inset: 0; background: #020202; z-index: 999999;
  display: flex; flex-direction: column; justify-content: flex-start;
  padding: 3rem; font-family: var(--font-code); color: var(--terminal);
  transition: opacity 0.6s ease-in-out, transform 0.6s ease-in-out;
}
.boot-line { font-size: 1.1rem; margin-bottom: 0.5rem; text-shadow: 0 0 8px var(--terminal); }
.boot-cursor { display: inline-block; width: 12px; height: 1.2em; background: var(--terminal); vertical-align: bottom; animation: blinker 1s infinite; box-shadow: 0 0 8px var(--terminal); }
@keyframes blinker { 50% { opacity: 0; } }

/* ── INTERACTIVE CANVAS BACKGROUND ── */
#nexusCanvas {
  position: fixed; top: 0; left: 0; width: 100vw; height: 100vh;
  z-index: -5; background: radial-gradient(circle at center, #0a0a12 0%, var(--bg-dark) 100%);
  pointer-events: auto;
}

/* ── PROGRESS BAR ── */
#reading-progress {
  position: fixed; top: 0; left: 0; height: 3px;
  background: linear-gradient(90deg, var(--primary), var(--secondary));
  z-index: 99999; width: 0%; box-shadow: var(--border-glow);
}

/* ── SCROLL REVEAL ── */
.reveal { opacity: 0; transform: translateY(30px); transition: all 0.7s cubic-bezier(0.16, 1, 0.3, 1); }
.reveal.visible { opacity: 1; transform: translateY(0); }
.delay-1 { transition-delay: 0.1s; }
.delay-2 { transition-delay: 0.2s; }

/* ── HUD GLASS CARDS ── */
.hud-card {
  background: var(--bg-card);
  backdrop-filter: blur(10px); -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  clip-path: polygon(20px 0, 100% 0, 100% calc(100% - 20px), calc(100% - 20px) 100%, 0 100%, 0 20px);
  padding: 2.5rem; transition: all 0.3s ease; position: relative;
}
.hud-card::before { content: ''; position: absolute; top: 0; left: 0; width: 0%; height: 3px; background: var(--primary); transition: width 0.4s ease; }
.hud-card:hover { border-color: rgba(0, 240, 255, 0.4); box-shadow: var(--border-glow); transform: translateY(-5px); }
.hud-card:hover::before { width: 100%; }

/* ── NAV ── */
nav { position: sticky; top: 0; z-index: 100; background: rgba(5, 5, 8, 0.85); backdrop-filter: blur(15px); border-bottom: 1px solid rgba(0,240,255,0.2); box-shadow: 0 5px 20px rgba(0,0,0,0.5); }
.nav-container { display: flex; align-items: center; justify-content: space-between; width: 100%; max-width: 1200px; padding: 1rem 2rem; margin: 0 auto; }
.nav-logo-section .widget { margin: 0; }
.nav-logo { font-family: var(--font-display); font-size: 1.6rem; font-weight: 900; color: #fff; letter-spacing: 2px; text-shadow: 0 0 10px rgba(255,255,255,0.3); }
.nav-logo span { color: var(--primary); text-shadow: 0 0 15px var(--primary); }

.nav-right { display: flex; align-items: center; gap: 2.5rem; }
.nav-links-wrapper .widget { margin: 0; }
.nav-links { display: flex; gap: 2rem; list-style: none; align-items: center; margin: 0; padding: 0; }
.nav-links a { font-family: var(--font-code); color: var(--text-main); font-size: 0.9rem; font-weight: 700; transition: color 0.2s; position: relative; }
.nav-links a:hover { color: var(--primary); text-shadow: 0 0 8px var(--primary); }
.nav-links a::after { content: ''; position: absolute; left: 0; bottom: -5px; width: 0; height: 2px; background: var(--primary); transition: width 0.3s; }
.nav-links a:hover::after { width: 100%; }

/* ── DROPDOWN ── */
.dropdown { position: relative; display: inline-block; }
.dropdown .dropbtn { cursor: pointer; display: flex; align-items: center; gap: 4px; }
.dropdown-content { display: none; position: absolute; background-color: var(--bg-card); border: 1px solid var(--primary); border-top: 3px solid var(--primary); min-width: 220px; top: 100%; left: -1rem; z-index: 101; padding: 0; box-shadow: 0 10px 30px rgba(0,0,0,0.9); }
.dropdown-content a { color: var(--text-main); padding: 1rem; display: block; font-family: var(--font-code); font-size: 0.85rem; border-bottom: 1px solid rgba(255,255,255,0.05); }
.dropdown-content a:hover { background-color: rgba(0,240,255,0.1); color: var(--primary); padding-left: 1.5rem; }
.dropdown:hover .dropdown-content { display: block; }

.hamburger { display: none; background: none; border: none; cursor: pointer; padding: 0.5rem; }
.hamburger svg { width: 30px; height: 30px; fill: var(--primary); filter: drop-shadow(0 0 5px var(--primary)); }

/* ── SEARCH BAR ── */
.search-form { display: flex; align-items: center; position: relative; }
.search-input { background: rgba(0,0,0,0.6); border: 1px solid rgba(255,255,255,0.2); color: var(--text-main); padding: 0.5rem 1rem 0.5rem 2.5rem; font-family: var(--font-code); font-size: 0.85rem; width: 180px; transition: all 0.3s ease; clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); }
.search-input::placeholder { color: var(--text-muted); }
.search-input:focus { outline: none; border-color: var(--primary); width: 220px; box-shadow: inset 0 0 10px rgba(0,240,255,0.2); }
.search-btn { position: absolute; left: 10px; background: none; border: none; padding: 0; display: flex; align-items: center; justify-content: center; cursor: pointer; }
.search-btn svg { width: 16px; height: 16px; fill: var(--text-muted); transition: fill 0.2s; }
.search-input:focus + .search-btn svg, .search-btn:hover svg { fill: var(--primary); }

/* ── GAMER BUTTONS ── */
.btn-primary, .btn-secondary {
  display: inline-flex; align-items: center; justify-content: center; gap: 10px; padding: 1rem 2.5rem;
  font-family: var(--font-display); font-weight: 700; font-size: 0.95rem; text-transform: uppercase; letter-spacing: 2px;
  text-decoration: none; cursor: pointer; position: relative; transition: all 0.3s ease;
  clip-path: polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px);
}
.btn-primary { background: var(--primary); color: #000 !important; border: none; box-shadow: 0 0 15px rgba(0,240,255,0.4); }
.btn-primary:hover { background: #fff; transform: scale(1.05); box-shadow: 0 0 25px var(--primary); }

.btn-secondary { background: rgba(176, 38, 255, 0.1); color: var(--secondary) !important; border: 1px solid var(--secondary); }
.btn-secondary:hover { background: var(--secondary); color: #fff !important; transform: scale(1.05); box-shadow: 0 0 25px var(--secondary); }

/* ── HERO ── */
.hero { min-height: 85vh; padding: 4rem 2rem; position: relative; display: flex; flex-direction: column; align-items: center; justify-content: center; z-index: 10; text-align: center; }
.hero-tag { display: inline-flex; align-items: center; gap: 8px; background: rgba(0,255,65,0.1); border: 1px solid var(--terminal); padding: 8px 20px; font-family: var(--font-code); font-size: 0.8rem; color: var(--terminal); margin-bottom: 2rem; clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); }
.hero-tag .dot { width: 8px; height: 8px; background: var(--terminal); animation: blinker 1s infinite; box-shadow: 0 0 10px var(--terminal); }
.hero-title { font-size: clamp(3rem, 6vw, 5.5rem); font-weight: 900; line-height: 1.1; margin-bottom: 1.5rem; text-shadow: 4px 4px 0 rgba(0,0,0,0.8); }
.hero-title span { color: transparent; -webkit-text-stroke: 2px var(--primary); text-shadow: 0 0 20px rgba(0,240,255,0.5); }
.hero-desc { font-size: 1.15rem; color: var(--text-muted); margin: 0 auto 3rem auto; max-width: 650px; line-height: 1.7; background: rgba(0,0,0,0.5); padding: 15px 25px; border-left: 3px solid var(--primary); backdrop-filter: blur(5px); }
.hero-actions { display: flex; gap: 1.5rem; flex-wrap: wrap; justify-content: center; }

/* ── SOCIAL BANNERS (STATIC/NO HOVER) ── */
.stats-yt-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; width: 100%; max-width: 1000px; margin-top: 5rem; z-index: 10; }
.social-banner { 
  background: var(--bg-card); backdrop-filter: blur(10px); -webkit-backdrop-filter: blur(10px);
  clip-path: polygon(20px 0, 100% 0, 100% calc(100% - 20px), calc(100% - 20px) 100%, 0 100%, 0 20px);
  display: flex; flex-direction: column; align-items: center; text-align: center; gap: 1.5rem; padding: 3rem 2rem;
  position: relative;
}
.social-banner::before { content: ''; position: absolute; top: 0; left: 0; width: 100%; height: 3px; background: var(--primary); }

.social-banner.git { border: 1px solid rgba(0, 240, 255, 0.3); box-shadow: inset 0 0 10px rgba(0, 240, 255, 0.1); }
.social-banner.git .icon { fill: var(--primary); filter: drop-shadow(0 0 10px var(--primary)); width: 55px; height: 55px; }

.social-banner.yt { border: 1px solid rgba(255, 0, 0, 0.3); box-shadow: inset 0 0 10px rgba(255, 0, 0, 0.1); }
.social-banner.yt::before { background: #ff0000; }
.social-banner.yt .icon { fill: #ff0000; filter: drop-shadow(0 0 10px #ff0000); width: 55px; height: 55px; }

.social-banner h2 { font-size: 1.4rem; font-weight: 700; margin-bottom: 0.5rem; }
.social-banner p { color: var(--text-muted); font-size: 0.95rem; line-height: 1.6; max-width: 280px; margin: 0 auto; text-align: center; }
.social-banner a { margin-top: auto; /* Aligns buttons to the bottom regardless of text length */ }

/* ── SECTIONS ── */
section.standard-section { padding: 6rem 2rem; max-width: 1100px; margin: 0 auto; width: 100%; position: relative; z-index: 10; }
/* Gap repair for blog section */
#blog.standard-section { padding-top: 3rem; }

.section-label { font-family: var(--font-code); font-size: 0.9rem; color: var(--secondary); font-weight: 700; text-transform: uppercase; margin-bottom: 0.5rem; display: flex; align-items: center; gap: 10px; }
.section-label::before { content: '/>'; color: var(--primary); }
.section-title { font-size: clamp(2.2rem, 4vw, 3.5rem); font-weight: 900; margin-bottom: 3rem; text-shadow: 2px 2px 5px rgba(0,0,0,0.8); }

/* ── ABOUT ── */
.about-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 3rem; }
.about-text { color: var(--text-main); font-size: 1.1rem; }
.about-text p { margin-bottom: 1.5rem; }
.about-text strong { color: var(--primary); }

.about-highlights { display: flex; flex-direction: column; gap: 1.5rem; }
.highlight-item { background: rgba(0,0,0,0.4); border-left: 3px solid var(--primary); padding: 1.25rem 1.5rem; display: flex; align-items: center; gap: 1.25rem; transition: all 0.3s; }
.highlight-item:hover { background: rgba(0,240,255,0.05); transform: translateX(10px); box-shadow: inset 0 0 15px rgba(0,240,255,0.1); }
.highlight-icon { font-size: 1.8rem; filter: drop-shadow(0 0 5px var(--primary)); }
.highlight-info strong { display: block; font-family: var(--font-display); font-size: 1rem; color: #fff; margin-bottom: 4px; letter-spacing: 1px; }
.highlight-info span { font-size: 0.9rem; color: var(--text-muted); font-family: var(--font-code); }

/* ── EXPERIENCE TIMELINE ── */
.timeline { position: relative; padding-left: 2rem; }
.timeline::before { content: ''; position: absolute; left: 0; top: 0; bottom: 0; width: 2px; background: rgba(255,255,255,0.1); }
.timeline-item { position: relative; margin-bottom: 3rem; }
.timeline-dot { position: absolute; left: -2.35rem; top: 0; width: 14px; height: 14px; background: var(--bg-dark); border: 2px solid var(--primary); transform: rotate(45deg); transition: all 0.3s; }
.timeline-item:hover .timeline-dot { background: var(--primary); box-shadow: 0 0 15px var(--primary); transform: rotate(135deg) scale(1.2); }
.timeline-body { @extend .hud-card; padding: 2rem; margin-top: -1rem; }
.timeline-period { font-family: var(--font-code); font-size: 0.85rem; color: var(--secondary); margin-bottom: 0.5rem; font-weight: 700; }
.timeline-role { font-family: var(--font-display); font-size: 1.4rem; font-weight: 700; color: #fff; margin-bottom: 0.25rem; }
.timeline-org { font-size: 1rem; color: var(--primary); margin-bottom: 1.25rem; font-weight: 600; }
.timeline-points { list-style: none; display: flex; flex-direction: column; gap: 0.8rem; }
.timeline-points li { font-size: 1rem; color: var(--text-main); position: relative; padding-left: 1.5rem; }
.timeline-points li::before { content: '>'; position: absolute; left: 0; color: var(--secondary); font-family: var(--font-code); font-weight: bold; }

/* ── PROJECTS ── */
.projects-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 2rem; }
.project-card { @extend .hud-card; display: flex; flex-direction: column; }
.project-date { font-family: var(--font-code); font-size: 0.8rem; color: var(--terminal); margin-bottom: 1rem; }
.project-name { font-family: var(--font-display); font-size: 1.3rem; font-weight: 700; color: #fff; margin-bottom: 1rem; }
.project-desc { font-size: 1.05rem; color: var(--text-muted); margin-bottom: 1.5rem; flex-grow: 1; line-height: 1.6; }
.project-link { font-family: var(--font-code); font-size: 0.9rem; font-weight: 700; color: var(--primary); text-transform: uppercase; display: inline-flex; align-items: center; gap: 5px; transition: gap 0.2s; }
.project-card:hover .project-link { gap: 10px; text-shadow: 0 0 8px var(--primary); }

/* ── SKILLS & CERTS ── */
.skills-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 1.5rem; }
.skill-category { @extend .hud-card; padding: 2rem; }
.skill-cat-title { font-family: var(--font-display); font-size: 1rem; color: var(--secondary); margin-bottom: 1.5rem; text-transform: uppercase; letter-spacing: 1px; border-bottom: 1px solid rgba(176, 38, 255, 0.3); padding-bottom: 8px; }
.skill-tags { display: flex; flex-wrap: wrap; gap: 10px; }
.skill-tag { padding: 6px 14px; background: rgba(0,0,0,0.5); border: 1px solid rgba(255,255,255,0.1); clip-path: polygon(8px 0, 100% 0, 100% calc(100% - 8px), calc(100% - 8px) 100%, 0 100%, 0 8px); font-family: var(--font-code); font-size: 0.85rem; color: var(--text-main); transition: all 0.3s; }
.skill-tag:hover { background: var(--primary); color: #000; border-color: var(--primary); box-shadow: 0 0 15px var(--primary); transform: scale(1.05); }

.certs-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 1.5rem; margin-top: 2rem; }
.cert-card { @extend .hud-card; padding: 1.5rem; border-top: 2px solid var(--secondary); }
.cert-issuer { font-family: var(--font-code); font-size: 0.8rem; color: var(--secondary); text-transform: uppercase; margin-bottom: 5px; }
.cert-name { font-size: 1.1rem; font-weight: 600; color: #fff; }

/* ── BLOG GRID ── */
.blog-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 2rem; }
.blog-card { @extend .hud-card; display: flex; flex-direction: column; padding: 2.5rem; }
.blog-date { font-family: var(--font-code); font-size: 0.85rem; color: var(--primary); margin-bottom: 1rem; }
.blog-title { font-family: var(--font-display); font-size: 1.3rem; font-weight: 700; margin-bottom: 1rem; line-height: 1.4; text-transform: none; }
.blog-title a { color: #fff; transition: color 0.3s; }
.blog-title a:hover { color: var(--primary); text-shadow: 0 0 10px var(--primary); }
.blog-snippet { font-size: 1.05rem; color: var(--text-muted); margin-bottom: 1.5rem; flex-grow: 1; }
.read-more { font-family: var(--font-code); font-weight: 700; font-size: 0.9rem; color: var(--secondary); display: inline-flex; align-items: center; gap: 5px; text-transform: uppercase; transition: all 0.3s; }
.blog-card:hover .read-more { gap: 10px; color: var(--primary); text-shadow: 0 0 8px var(--primary); }

/* ── FULL POST VIEW ── */
.post-container { @extend .hud-card; max-width: 900px; margin: 2rem auto; padding: 4rem; }
@media (max-width: 768px) { .post-container { padding: 2rem 1.5rem; } }

.post-header { text-align: center; margin-bottom: 3rem; border-bottom: 1px dashed rgba(255,255,255,0.1); padding-bottom: 2rem; }
.post-header h1 { font-size: clamp(2rem, 5vw, 3.5rem); font-weight: 900; margin: 1rem 0; line-height: 1.2; text-shadow: 2px 2px 0px var(--secondary); }
.post-meta-tags { display: flex; flex-wrap: wrap; justify-content: center; gap: 1rem; font-family: var(--font-code); font-size: 0.9rem; color: var(--text-muted); margin-top: 1.5rem; }
.post-tag { color: var(--primary); border: 1px solid rgba(0,240,255,0.3); padding: 2px 8px; border-radius: 4px; }

.post-hero-image { width: 100%; aspect-ratio: 16 / 9; overflow: hidden; clip-path: polygon(20px 0, 100% 0, 100% calc(100% - 20px), calc(100% - 20px) 100%, 0 100%, 0 20px); border: 1px solid var(--primary); margin: 0 auto 3rem auto; box-shadow: 0 0 20px rgba(0,240,255,0.1); }
.post-hero-image img { width: 100% !important; height: 100% !important; object-fit: cover !important; transition: transform 0.5s; }
.post-hero-image:hover img { transform: scale(1.05); }

.post-body .separator, .post-body img { display: none !important; }
.post-body { font-size: 1.15rem; color: var(--text-main); line-height: 1.8; }
.post-body h2, .post-body h3 { font-family: var(--font-display); font-weight: 700; margin: 3rem 0 1.5rem; color: var(--primary); text-shadow: 0 0 10px rgba(0,240,255,0.3); }
.post-body p { margin-bottom: 1.5rem; color: #cbd5e1; }
.post-body a { color: var(--secondary); border-bottom: 1px dashed var(--secondary); transition: all 0.3s; }
.post-body a:hover { color: #fff; border-bottom-style: solid; background: rgba(176,38,255,0.2); box-shadow: 0 0 10px rgba(176,38,255,0.5); }

.post-body blockquote { border-left: 4px solid var(--secondary); background: rgba(176,38,255,0.05); padding: 1.5rem 2rem; margin: 2.5rem 0; font-style: italic; clip-path: polygon(0 0, 100% 0, 100% 100%, 20px 100%, 0 calc(100% - 20px)); }
.post-body pre { background: #000; border: 1px solid rgba(255,255,255,0.1); padding: 1.5rem; overflow-x: auto; margin: 2.5rem 0; clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); }
.post-body code { font-family: var(--font-code); font-size: 0.95rem; color: var(--terminal); }

/* ── CONTACT ── */
.contact-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 3rem; }
.contact-info { display: flex; flex-direction: column; gap: 1.5rem; }
.contact-item { background: rgba(0,0,0,0.5); border: 1px solid rgba(255,255,255,0.1); clip-path: polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px); padding: 1.5rem; display: flex; align-items: center; gap: 1.5rem; transition: all 0.3s; }
.contact-icon { font-size: 1.8rem; filter: drop-shadow(0 0 8px var(--primary)); color: #fff; display: flex; align-items: center; }
.contact-item:hover { border-color: var(--primary); background: rgba(0,240,255,0.05); transform: translateX(10px); box-shadow: inset 0 0 15px rgba(0,240,255,0.2); }
.contact-label { font-family: var(--font-code); font-size: 0.85rem; color: var(--primary); margin-bottom: 4px; text-transform: uppercase; }
.contact-value { font-size: 1.1rem; font-weight: 600; color: #fff; }

/* ── ENHANCED CONTACT CARD (Ready to Collaborate - STATIC NO HOVER) ── */
.contact-card { 
  background: var(--bg-card);
  backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px);
  clip-path: polygon(20px 0, 100% 0, 100% calc(100% - 20px), calc(100% - 20px) 100%, 0 100%, 0 20px);
  display: flex; flex-direction: column; justify-content: center; gap: 1.2rem; 
  border: 1px solid rgba(176, 38, 255, 0.5); 
  background: linear-gradient(135deg, rgba(176,38,255,0.15) 0%, rgba(0,0,0,0.9) 100%);
  box-shadow: inset 0 0 20px rgba(176,38,255,0.1), 0 10px 30px rgba(0,0,0,0.6);
  padding: 3rem 2.5rem; position: relative;
}
.contact-card::before { 
  content: ''; position: absolute; top: 0; left: 0; width: 100%; height: 3px; 
  background: var(--secondary); 
}
.contact-card-label { 
  font-family: var(--font-code); font-size: 0.85rem; color: var(--secondary); 
  letter-spacing: 2px; margin-bottom: -0.5rem; text-transform: uppercase; 
  display: flex; align-items: center; gap: 8px; 
}
.contact-card-label::before { 
  content: ''; display: inline-block; width: 8px; height: 8px; 
  background: var(--secondary); animation: blinker 1.5s infinite; 
  box-shadow: 0 0 8px var(--secondary);
}
.contact-card h3 { 
  font-size: 2.2rem; font-weight: 900; color: #fff; 
  text-shadow: 2px 2px 0px rgba(176,38,255,0.5); letter-spacing: 1px; 
}
.contact-card p { 
  font-size: 1.05rem; color: var(--text-main); line-height: 1.8; 
  border-left: 3px solid var(--secondary); padding: 1rem 1.2rem; 
  background: rgba(176,38,255,0.08); text-align: justify;
  border-radius: 0 8px 8px 0; margin-bottom: 0.5rem;
}

/* ── ADS BLOCKS ── */
.ad-sponsor-block {
  margin: 2rem auto; text-align: center; min-height: 100px; 
  background: rgba(0,0,0,0.8); border: 1px dashed var(--alert);
  clip-path: polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px);
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  position: relative; padding: 1.5rem; z-index: 10;
}
.ad-sponsor-label {
  position: absolute; top: -1px; left: 20px; background: var(--alert); color: #fff;
  font-family: var(--font-code); font-size: 0.75rem; padding: 2px 10px; font-weight: bold;
  clip-path: polygon(0 0, 100% 0, 90% 100%, 0% 100%);
}

/* ── FOOTER & SOCIAL ICONS ── */
.site-footer { border-top: 2px solid var(--primary); background: rgba(5,5,10,0.95); padding: 4rem 2rem 2rem; margin-top: 5rem; position: relative; z-index: 10; text-align: center; box-shadow: 0 -10px 30px rgba(0,240,255,0.1); }
.footer-bottom { max-width: 1200px; margin: 0 auto; display: flex; flex-direction: column; gap: 2.5rem; align-items: center; }

.social-links { display: flex; gap: 1.25rem; justify-content: center; flex-wrap: wrap; }
.social-icon { display: flex; align-items: center; justify-content: center; width: 50px; height: 50px; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); clip-path: polygon(25% 0%, 75% 0%, 100% 50%, 75% 100%, 25% 100%, 0% 50%); color: var(--text-main); transition: all 0.3s ease; }
.social-icon svg { width: 22px; height: 22px; fill: currentColor; }
.social-icon:hover { transform: scale(1.15) rotate(10deg); background: var(--bg-card); color: #fff; }

/* Brand Specific Neon Glows */
.social-icon.insta:hover { border-color: #E1306C; color: #E1306C; box-shadow: 0 0 15px rgba(225, 48, 108, 0.5); }
.social-icon.yt:hover { border-color: #FF0000; color: #FF0000; box-shadow: 0 0 15px rgba(255, 0, 0, 0.5); }
.social-icon.tg:hover { border-color: #0088cc; color: #0088cc; box-shadow: 0 0 15px rgba(0, 136, 204, 0.5); }
.social-icon.in:hover { border-color: #0A66C2; color: #0A66C2; box-shadow: 0 0 15px rgba(10, 102, 194, 0.5); }
.social-icon.be:hover { border-color: #1769ff; color: #1769ff; box-shadow: 0 0 15px rgba(23, 105, 255, 0.5); }
.social-icon.git:hover { border-color: var(--primary); color: var(--primary); box-shadow: 0 0 15px var(--primary); }

.footer-text { font-family: var(--font-code); font-size: 0.9rem; color: var(--text-muted); display: flex; flex-wrap: wrap; justify-content: center; align-items: center; gap: 2rem; width: 100%; border-top: 1px solid rgba(255,255,255,0.1); padding-top: 2rem; }
.inline-legal-links { display: flex; gap: 1.5rem; }
.inline-legal-links a { transition: color 0.2s; }
.inline-legal-links a:hover { color: var(--primary); text-shadow: 0 0 5px var(--primary); }
.footer-credit span { color: var(--secondary); font-weight: bold; text-shadow: 0 0 5px var(--secondary); }

/* ── MOBILE VIEW ── */
@media (max-width: 768px) {
  #boot-screen { padding: 2rem 1rem; }
  .hero { padding: 6rem 1.5rem 3rem; }
  .hero-title { font-size: 2.8rem; }
  .stats-yt-grid, .about-grid, .contact-grid { grid-template-columns: 1fr; }
  .hamburger { display: block; }
  .nav-right {
    display: none; position: absolute; top: 100%; left: 0; width: 100%;
    background: rgba(5,5,8,0.95); backdrop-filter: blur(10px); border-bottom: 2px solid var(--primary);
    flex-direction: column; padding: 2rem; gap: 1.5rem; z-index: 100; box-shadow: 0 10px 30px rgba(0,0,0,0.8);
  }
  .nav-right.active { display: flex; }
  .nav-links { flex-direction: column; width: 100%; gap: 1.5rem; }
  .search-form { width: 100%; order: -1; margin-bottom: 0.5rem; }
  .search-input { width: 100%; }
  .dropdown-content { position: static; box-shadow: none; border: none; border-left: 2px solid var(--primary); padding-left: 1rem; margin-top: 1rem; background: transparent; display: none; }
  .dropdown:hover .dropdown-content { display: block; }
  .footer-text { flex-direction: column; gap: 1rem; text-align: center; }
}

/* ── SCROLLBAR ── */
::-webkit-scrollbar { width: 8px; }
::-webkit-scrollbar-track { background: var(--bg-dark); }
::-webkit-scrollbar-thumb { background: rgba(0,240,255,0.3); border: 1px solid var(--primary); }
::-webkit-scrollbar-thumb:hover { background: var(--primary); }

body.script:
//
  /* ── COMMAND LINE BOOT SEQUENCE (LOADER) ── */
  const bootScreen = document.getElementById('boot-screen');
  const terminalText = document.getElementById('terminal-text');

  if (!sessionStorage.getItem('booted')) {
      const bootLines = [
          "INITIALIZING SYSTEM CORE... [OK]",
          "MOUNTING VIRTUAL DRIVES... [OK]",
          "LOADING NEURAL NETWORKS... [OK]",
          "BYPASSING MAINFRAME... [ACCESS GRANTED]",
          "WELCOME, ADMIN."
      ];

      let lineIndex = 0;
      function typeLine() {
          if (lineIndex < bootLines.length) {
              const p = document.createElement('div');
              p.className = 'boot-line';
              p.textContent = "> " + bootLines[lineIndex];
              terminalText.appendChild(p);
              lineIndex++;
              setTimeout(typeLine, Math.random() * 300 + 200); 
          } else {
              setTimeout(() => {
                  bootScreen.style.opacity = '0';
                  bootScreen.style.transform = 'scale(1.05)';
                  setTimeout(() => { 
                      bootScreen.style.display = 'none'; 
                      sessionStorage.setItem('booted', 'true');
                  }, 600);
              }, 800);
          }
      }
      setTimeout(typeLine, 500); 
  } else {
      bootScreen.style.display = 'none'; 
  }

  /* ── INTERACTIVE NEXUS (PARTICLE NETWORK) BACKGROUND ── */
  const canvas = document.getElementById('nexusCanvas');
  if (canvas) {
      const ctx = canvas.getContext('2d');
      let particlesArray;

      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;

      let mouse = { x: null, y: null, radius: (canvas.height/80) * (canvas.width/80) };

      window.addEventListener('mousemove', function(event) {
          mouse.x = event.x;
          mouse.y = event.y;
      });

      class Particle {
          constructor(x, y, directionX, directionY, size, color) {
              this.x = x;
              this.y = y;
              this.directionX = directionX;
              this.directionY = directionY;
              this.size = size;
              this.color = color;
          }
          draw() {
              ctx.beginPath();
              ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2, false);
              ctx.fillStyle = this.color;
              ctx.fill();
          }
          update() {
              if (this.x > canvas.width || this.x < 0) { this.directionX = -this.directionX; }
              if (this.y > canvas.height || this.y < 0) { this.directionY = -this.directionY; }

              let dx = mouse.x - this.x;
              let dy = mouse.y - this.y;
              let distance = Math.sqrt(dx*dx + dy*dy);
              if (distance < mouse.radius + this.size) {
                  if (mouse.x < this.x && this.x < canvas.width - this.size * 10) { this.x += 5; }
                  if (mouse.x > this.x && this.x > this.size * 10) { this.x -= 5; }
                  if (mouse.y < this.y && this.y < canvas.height - this.size * 10) { this.y += 5; }
                  if (mouse.y > this.y && this.y > this.size * 10) { this.y -= 5; }
              }
              this.x += this.directionX;
              this.y += this.directionY;
              this.draw();
          }
      }

      function init() {
          particlesArray = [];
          let numberOfParticles = (canvas.height * canvas.width) / 12000;
          for (let i = 0; i < numberOfParticles; i++) {
              let size = (Math.random() * 2) + 1;
              let x = (Math.random() * ((innerWidth - size * 2) - (size * 2)) + size * 2);
              let y = (Math.random() * ((innerHeight - size * 2) - (size * 2)) + size * 2);
              let directionX = (Math.random() * 1) - 0.5;
              let directionY = (Math.random() * 1) - 0.5;
              let color = '#00f0ff';
              particlesArray.push(new Particle(x, y, directionX, directionY, size, color));
          }
      }

      function connect() {
          let opacityValue = 1;
          for (let a = 0; a < particlesArray.length; a++) {
              for (let b = a; b < particlesArray.length; b++) {
                  let distance = ((particlesArray[a].x - particlesArray[b].x) * (particlesArray[a].x - particlesArray[b].x)) + ((particlesArray[a].y - particlesArray[b].y) * (particlesArray[a].y - particlesArray[b].y));
                  if (distance < (canvas.width/7) * (canvas.height/7)) {
                      opacityValue = 1 - (distance / 20000);
                      ctx.strokeStyle = 'rgba(0, 240, 255,' + opacityValue + ')';
                      ctx.lineWidth = 1;
                      ctx.beginPath();
                      ctx.moveTo(particlesArray[a].x, particlesArray[a].y);
                      ctx.lineTo(particlesArray[b].x, particlesArray[b].y);
                      ctx.stroke();
                  }
              }
          }
      }

      function animate() {
          requestAnimationFrame(animate);
          ctx.clearRect(0, 0, innerWidth, innerHeight);
          for (let i = 0; i < particlesArray.length; i++) {
              particlesArray[i].update();
          }
          connect();
      }

      window.addEventListener('resize', function() {
          canvas.width = innerWidth;
          canvas.height = innerHeight;
          mouse.radius = ((canvas.height/80) * (canvas.height/80));
          init();
      });

      init();
      animate();
  }

  /* ── MOBILE MENU ── */
  function toggleMenu() {
    const navMenu = document.getElementById('nav-menu');
    navMenu.classList.toggle('active');
  }

  /* ── SCROLL REVEAL ── */
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        e.target.classList.add('visible');
        observer.unobserve(e.target);
      }
    });
  }, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });

  const revealElements = document.querySelectorAll('.reveal');
  if(revealElements.length > 0) {
      revealElements.forEach(el => observer.observe(el));
  }

  /* ── READING PROGRESS BAR ── */
  window.addEventListener('scroll', () => {
    const winScroll = document.body.scrollTop || document.documentElement.scrollTop;
    const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const scrolled = (winScroll / height) * 100;
    const progressBar = document.getElementById('reading-progress');
    if (progressBar) progressBar.style.width = scrolled + '%';
  });

  /* ── CLEANUP LEFTOVER SPACES ── */
  document.addEventListener("DOMContentLoaded", function() {
    if (document.querySelector('.post-container')) {
      const postBodies = document.querySelectorAll('.post-body');
      postBodies.forEach(body => {
        let node = body.firstChild;
        while (node) {
          let next = node.nextSibling;
          if (node.nodeName === 'BR' || 
             (node.nodeType === 3 && node.textContent.trim() === '') ||
             (node.classList && node.classList.contains('separator')) ||
             (node.nodeName === 'P' && node.innerHTML.trim() === '')) {
            node.remove();
          } else {
            break;
          }
          node = next;
        }
      });
    }
  });
//
